func (j *sessionConnectionCleanupJob) Run(ctx context.Context) error {
	const op = "controller.sessionConnectionCleanupJob.Run"

	var (
		cursor   *string
		allClosed bool
	)

	for {
		connRepos, err := j.connectionRepoFn()
		if err != nil {
			return fmt.Errorf("%s: error getting connection repo: %w", op, err)
		}

		// Query for sessions that were authorized more than gracePeriod ago
		// and have not had a status update in that time.
		opts := []db.Option{
			db.WithFilterAttribute("session.status", StatusAuthorized),
			db.WithFilterAttribute("session.status", StatusConnected),
			db.WithFilterAttribute("session.connection.status", StatusClosed),
			WithDeadWorkerConnCloseMinGrace(j.gracePeriod),
		}
		if cursor != nil {
			opts = append(opts, WithCursor(*cursor))
		}

		sessions, cursor, err := connRepos.SessionRepo().QuerySessions(ctx, opts...)
		if err != nil {
			return fmt.Errorf("%s: error querying sessions: %w", op, err)
		}

		for _, sess := range sessions {
			if err := connRepos.SessionRepo().UpdateSession(ctx, sess.GetPublicId(), sess.Version, []Option{}...); err != nil {
				return fmt.Errorf("%s: error updating session: %w", op, err)
			}
			j.totalClosed++
		}

		if cursor == nil {
			break
		}
	}

	return nil
}

